#include<bits/stdc++.h>
using namespace std;
struct node
{
    long long x,y,z;
    long long cnt,ans,id;
}a[4000010];
bool flag[4000010];
long long lowbit(long long x)
{
    return x&-x;
}
long long sum[4000010];
long long ans[4000010],n,tot;
void update(long long x,long long v)
{
    for(long long i=x;i<=4000000;i+=lowbit(i))
    {
        sum[i]+=v;
    }
}
long long query(long long x)
{
    long long ans=0;
    for(long long i=x;i>=1;i-=lowbit(i))
    {
        ans+=sum[i];
    }
    return ans;
}
bool cmpx(node a,node b)
{
    return a.x<b.x||(a.x==b.x&&a.y<b.y)||(a.x==b.x&&a.y==b.y&&a.z<b.z);
}
bool cmpy(node a,node b)
{
    return a.y<b.y||(a.y==b.y&&a.z<b.z);
}
void cdq(long long l,long long r)
{
    if(l==r)
    {
        return;
    }
    long long mid=(l+r)>>1;
    cdq(l,mid);
    cdq(mid+1,r);
    sort(a+l,a+1+mid,cmpy);
    sort(a+mid+1,a+1+r,cmpy);
    long long i=l,j=mid+1;
    while(j<=r)
    {
        while(i<=mid&&a[i].y<=a[j].y)
        {
            update(a[i].z,a[i].cnt);
            i++;
        }
        a[j].ans+=query(a[j].z);
        j++;
    }
    for(long long k=l;k<i;k++)
    {
        update(a[k].z,-a[k].cnt);
    }
}
long long tim=1;
void addquery(long long x,long long y,long long id)
{
    tot++;
    tim++;
    a[tot].z=tim*2+1;
    a[tot].x=x;
    a[tot].y=y;
    a[tot].cnt=0;
    a[tot].id=id;
}
int main()
{
    scanf("%*d%lld",&n);
    long long p=0;
    while(1)
    {
        long long op;
        scanf("%lld",&op);
        if(op==3)
        {
            break;
        }
        if(op==1)
        {
            tot++;
            scanf("%lld%lld%lld",&a[tot].x,&a[tot].y,&a[tot].cnt);
            a[tot].z=(tim+1)*2;
        }
        else
        {
            p++;
            long long ax,bx,ay,by;
            scanf("%lld%lld%lld%lld",&ax,&ay,&bx,&by);
            addquery(bx,by,p);
            addquery(bx,ay-1,-p);
            addquery(ax-1,by,-p);
            addquery(ax-1,ay-1,p);
        }
    }
    sort(a+1,a+1+tot,cmpx);
    cdq(1,tot);
    for(long long i=1;i<=tot;i++)
    {
        if(a[i].id<0)
        {
            ans[-a[i].id]-=a[i].ans;
            continue;
        }
        ans[a[i].id]+=a[i].ans;
    }
    for(long long i=1;i<=p;i++)
    {
        printf("%lld\n",ans[i]);
    }
    return 0;
}
